import{_ as t,o as e,c as s,ae as n}from"./chunks/framework.CF3ehLaw.js";const u=JSON.parse('{"title":"物流系统终端机器人 — 首响应延迟优化（接力交接 v2）","description":"","frontmatter":{},"headers":[],"relativePath":"background01.md","filePath":"background01.md"}'),l={name:"background01.md"};function i(r,a,o,p,d,c){return e(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="物流系统终端机器人-—-首响应延迟优化-接力交接-v2" tabindex="-1">物流系统终端机器人 — 首响应延迟优化（接力交接 v2） <a class="header-anchor" href="#物流系统终端机器人-—-首响应延迟优化-接力交接-v2" aria-label="Permalink to &quot;物流系统终端机器人 — 首响应延迟优化（接力交接 v2）&quot;">​</a></h1><h2 id="★-开发模式-必须明确-最重要" tabindex="-1">★ 开发模式（必须明确，最重要！） <a class="header-anchor" href="#★-开发模式-必须明确-最重要" aria-label="Permalink to &quot;★ 开发模式（必须明确，最重要！）&quot;">​</a></h2><p>双设备开发：</p><ul><li>PC（Ubuntu 24.04）只写代码，缺项目运行依赖</li><li>通过 syncpi 同步到开发板（Ubuntu 22.04）运行</li><li>所有性能数据来自开发板实测，不要尝试在 PC 本地启动/测试</li><li>ROS humble 是给开发板的，不是写错</li><li>任何&quot;测试一下&quot;都意味着请用户 syncpi 后跑，等用户告诉你结果</li><li>PC 上 curl 外部 API（dashscope 等）可以做，那是网络请求不是项目代码</li></ul><hr><h2 id="项目定位" tabindex="-1">项目定位 <a class="header-anchor" href="#项目定位" aria-label="Permalink to &quot;项目定位&quot;">​</a></h2><p>多无人机协同物流系统的智能终端机器人（嵌入式开发板 + 平板 WebView 展示端），核心是无人机起飞/降落、SLAM 建图查看。不是个人桌面助手（fork 自 py-xiaozhi 已大幅瘦身）。</p><hr><h2 id="已完成的优化路径" tabindex="-1">已完成的优化路径 <a class="header-anchor" href="#已完成的优化路径" aria-label="Permalink to &quot;已完成的优化路径&quot;">​</a></h2><h3 id="阶段时延演变" tabindex="-1">阶段时延演变 <a class="header-anchor" href="#阶段时延演变" aria-label="Permalink to &quot;阶段时延演变&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>首响应</th><th>主要改动</th></tr></thead><tbody><tr><td>基线</td><td>5.9s</td><td>—</td></tr><tr><td>LLM 流式 + 句级 TTS</td><td>~3.86s</td><td>agent.run_streaming()</td></tr><tr><td>砍工具 + warmup 修复</td><td>~3.97s</td><td>40 → 6 个工具</td></tr><tr><td>三层路由（本次）</td><td>待开发板实测</td><td>Tier 0 / Tier 1 / Tier 2</td></tr></tbody></table><h3 id="关键发现-llm-ttfb-是端点限制-不是-prompt-长度" tabindex="-1">关键发现：LLM TTFB 是端点限制，不是 prompt 长度 <a class="header-anchor" href="#关键发现-llm-ttfb-是端点限制-不是-prompt-长度" aria-label="Permalink to &quot;关键发现：LLM TTFB 是端点限制，不是 prompt 长度&quot;">​</a></h3><p>实测：砍 70% prompt（9908 → 3005 token）TTFB 没降（1700ms → 1700ms）。说明 prefill 不是大头，模型路由 + 首 token 生成才是 dashscope coding.dashscope.aliyuncs.com 端点（qwen3-coder-next）的固有延迟。</p><h3 id="模型选型实测-pc-端-curl-非项目代码" tabindex="-1">模型选型实测（PC 端 curl，非项目代码） <a class="header-anchor" href="#模型选型实测-pc-端-curl-非项目代码" aria-label="Permalink to &quot;模型选型实测（PC 端 curl，非项目代码）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模型</th><th>TTFB 中位数</th><th>备注</th></tr></thead><tbody><tr><td>qwen-flash</td><td>332ms</td><td>✅ 选用，便宜稳定</td></tr><tr><td>qwen-turbo</td><td>366ms</td><td>持平</td></tr><tr><td>qwen-plus</td><td>550-625ms</td><td>慢</td></tr><tr><td>qwen-long</td><td>700-770ms</td><td>慢</td></tr><tr><td>qwen2.5-3b/7b-instruct</td><td>392-647ms</td><td>方差大</td></tr><tr><td>qwen3-coder-next（旧路径）</td><td>~1700ms</td><td>端点固有延迟</td></tr></tbody></table><hr><h2 id="本次落地的三层路由架构" tabindex="-1">本次落地的三层路由架构 <a class="header-anchor" href="#本次落地的三层路由架构" aria-label="Permalink to &quot;本次落地的三层路由架构&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>STT 文本</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>[Tier 0] 关键词意图直达（0 LLM，目标 &lt;1s）</span></span>
<span class="line"><span>  起飞/降落/地图/电量 → 直接调 MCP 工具</span></span>
<span class="line"><span>  命令型：先 ack TTS + 异步执行工具</span></span>
<span class="line"><span>  查询型：等工具结果 → 播报</span></span>
<span class="line"><span>  ↓ 未命中</span></span>
<span class="line"><span>[Tier 2 直达] tier2_keywords 命中（当前空 list，留 hook）</span></span>
<span class="line"><span>  → 跳过 Tier 1 直接 coder-next + tools</span></span>
<span class="line"><span>  ↓ 未命中</span></span>
<span class="line"><span>[Tier 1] qwen-flash + 项目背景 prompt + 无 tools</span></span>
<span class="line"><span>  流式扫描前 30 字符</span></span>
<span class="line"><span>  命中 fallback 短语（&quot;做不了/没办法处理/我不会&quot;）→ 静默丢弃 → Tier 2</span></span>
<span class="line"><span>  否则正常切句推 TTS</span></span>
<span class="line"><span>  ↓ fallback 触发</span></span>
<span class="line"><span>[Tier 2] qwen3-coder-next + 完整 tools（原路径）</span></span></code></pre></div><h3 id="改动文件清单" tabindex="-1">改动文件清单 <a class="header-anchor" href="#改动文件清单" aria-label="Permalink to &quot;改动文件清单&quot;">​</a></h3><table tabindex="0"><thead><tr><th>文件</th><th>改动</th></tr></thead><tbody><tr><td>config/config.json</td><td>加 LLM_FAST / INTENT_KEYWORDS / ROUTER 三段</td></tr><tr><td>src/llm/llm_client.py</td><td><strong>init</strong>(config_section=&quot;LLM&quot;) 支持双实例 + model property</td></tr><tr><td>src/protocols/intent_matcher.py</td><td>新文件：match_intent() / match_tier2_direct()</td></tr><tr><td>src/protocols/local_agent_protocol.py</td><td>_run_agent_pipeline_after_stt 重写为三层；新增 _run_tier0_intent / _run_tier1_fast / _run_tier2_full</td></tr></tbody></table><h3 id="关键设计决策" tabindex="-1">关键设计决策 <a class="header-anchor" href="#关键设计决策" aria-label="Permalink to &quot;关键设计决策&quot;">​</a></h3><ul><li>Tier 1 不走 agent：直接用 LLMClient + 拼装 history，避免 fallback 时 history 双 append</li><li>Tier 1 fallback 前完全没推 TTS：用户不会听到一半切换</li><li>ROUTER.fast_path_enabled 开关：翻车一键回退老路径</li><li>_llm_fast 单例懒加载：首次 Tier 1 才构造</li><li>Tier 0 命令型用 asyncio.create_task 异步执行工具：不阻塞 ack 播放</li></ul><hr><h2 id="已就位的代码-之前阶段-本次" tabindex="-1">已就位的代码（之前阶段 + 本次） <a class="header-anchor" href="#已就位的代码-之前阶段-本次" aria-label="Permalink to &quot;已就位的代码（之前阶段 + 本次）&quot;">​</a></h2><h3 id="llm-层" tabindex="-1">LLM 层 <a class="header-anchor" href="#llm-层" aria-label="Permalink to &quot;LLM 层&quot;">​</a></h3><ul><li>src/llm/llm_client.py — chat_completion(stream=True) 返回 AsyncStream，含 prompt token 估算 + TTFB 埋点；支持 config_section 双实例</li><li>src/llm/agent.py — run_streaming() 异步生成器，工具调用轮非流式 / 文字轮流式</li></ul><h3 id="协议层" tabindex="-1">协议层 <a class="header-anchor" href="#协议层" aria-label="Permalink to &quot;协议层&quot;">​</a></h3><ul><li>src/protocols/local_agent_protocol.py <ul><li>_take_complete_segment() 增长缓冲按强标点切句</li><li>_tts_sink_one_segment() 单段合成+推送</li><li>_consume_llm_stream_to_remote_tts() 消费 token 流即时推 TTS</li><li>_kick_edge_tts_warmup() 与 LLM 并行做 TLS 握手（warmup 文本必须有可朗读字符，&quot;。&quot; 不行用 &quot;嗯。&quot;）</li><li>_clean_text_for_tts() 已扩展剥离 ～——•★ 等装饰符号</li></ul></li></ul><h3 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h3><ul><li>STT.vad_min_silence_duration_ms: 300（从 500）</li><li>LLM.optional_tool_groups: [] —— 改成 [&quot;calendar&quot;,&quot;timer&quot;,&quot;music&quot;,&quot;web&quot;] 任一组就恢复</li></ul><hr><h2 id="当前激活的工具" tabindex="-1">当前激活的工具 <a class="header-anchor" href="#当前激活的工具" aria-label="Permalink to &quot;当前激活的工具&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>drone.takeoff drone.land drone.status mapping.view self_audio_speaker_set_volume self_audio_speaker_get_volume</span></span></code></pre></div><p>源码保留但不注册的：calendar / timer / music / web / camera（和 SceneMonitor）/ screenshot / bazi / system.application</p><hr><h2 id="待办-下一阶段优先级" tabindex="-1">待办（下一阶段优先级） <a class="header-anchor" href="#待办-下一阶段优先级" aria-label="Permalink to &quot;待办（下一阶段优先级）&quot;">​</a></h2><h3 id="p0-—-开发板实测三层路由" tabindex="-1">P0 — 开发板实测三层路由 <a class="header-anchor" href="#p0-—-开发板实测三层路由" aria-label="Permalink to &quot;P0 — 开发板实测三层路由&quot;">​</a></h3><p>把 PC 上写的代码 syncpi 到开发板，验证三个场景：</p><ol><li>Tier 0：说&quot;起飞&quot; / &quot;电量&quot; <ul><li>期望日志：[Tier0] 命中关键词 ...</li><li>期望首响应：&lt; 1s</li></ul></li><li>Tier 1：说&quot;今天心情不错&quot; / &quot;你叫什么&quot; <ul><li>期望日志：[Tier1] flash 完成 总耗时=Xms</li><li>期望首响应：~1.5-2s（TTFB 332ms + TTS 950ms + 切句开销）</li></ul></li><li>Tier 1 → Tier 2 fallback：说&quot;分析一下今天的飞行日志&quot; <ul><li>期望日志：[Tier1] 命中 fallback 短语 ... → Tier 2</li><li>期望走原 coder-next 路径</li></ul></li></ol><p>根据实测数据决定后续动作。</p><h3 id="p1-—-填-tier-2-直达关键词词表-依赖-p0-实测结论" tabindex="-1">P1 — 填 Tier 2 直达关键词词表（依赖 P0 实测结论） <a class="header-anchor" href="#p1-—-填-tier-2-直达关键词词表-依赖-p0-实测结论" aria-label="Permalink to &quot;P1 — 填 Tier 2 直达关键词词表（依赖 P0 实测结论）&quot;">​</a></h3><p>现在 ROUTER.tier2_keywords = [] 空。等用户测完 Tier 1 实际能力边界后，把 flash 答不出的高级语义类关键词填进去（候选：日志/分析/调度/对比/汇总/故障/规划），跳过 Tier 1 直接走 Tier 2 省 ~400ms fallback 开销。</p><p>词表尺度原则：宁可漏（高级问题误走 Tier 1 → fallback 多 400ms）不可错（闲聊误走 Tier 2 → 慢 1.3s）。不放&quot;怎么/如何&quot;等闲聊也常用的词。</p><h3 id="p1-—-常态化-ros-bridge" tabindex="-1">P1 — 常态化 ROS Bridge <a class="header-anchor" href="#p1-—-常态化-ros-bridge" aria-label="Permalink to &quot;P1 — 常态化 ROS Bridge&quot;">​</a></h3><p>src/mcp/tools/robot_dispatch/tools.py:_publish_int_fire_and_forget 每次 subprocess.Popen 启 Python + import rclpy，冷启动 1-1.5s。改造为主进程驻留 publisher 单例（rclpy 已经在主进程跑 SLAM bridge）。和 Tier 0 配套，让&quot;起飞&quot;真正达到 0.7s。</p><h3 id="p2-—-qwen-tts-实测-可能不做" tabindex="-1">P2 — qwen-tts 实测（可能不做） <a class="header-anchor" href="#p2-—-qwen-tts-实测-可能不做" aria-label="Permalink to &quot;P2 — qwen-tts 实测（可能不做）&quot;">​</a></h3><p>edge-tts 段 0 首块 ~950ms 是当前 TTS 瓶颈。src/tts/qwen_tts_client.py 已存在但只产 Opus 帧，要先加 WAV 输出 + 实测首块延迟。</p><ul><li>qwen 首块 &lt; 500ms → 切</li><li>≈ 800ms → 不切</li><li>&lt; 300ms → 进一步上 qwen-tts 真流式</li></ul><h3 id="p3-—-带参数关键词-暂不做" tabindex="-1">P3 — 带参数关键词（暂不做） <a class="header-anchor" href="#p3-—-带参数关键词-暂不做" aria-label="Permalink to &quot;P3 — 带参数关键词（暂不做）&quot;">​</a></h3><p>如&quot;音量调到 70&quot; / &quot;起飞到 5 米&quot;。开始引入复杂度，等核心三层路由稳了再加。</p><hr><h2 id="关键埋点日志-验证改动用" tabindex="-1">关键埋点日志（验证改动用） <a class="header-anchor" href="#关键埋点日志-验证改动用" aria-label="Permalink to &quot;关键埋点日志（验证改动用）&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[工具列表] 共 N 个工具传给 LLM：[...]</span></span>
<span class="line"><span>[LLM/prompt] 估 token: msg=X tool=Y total≈Z</span></span>
<span class="line"><span>[LLM/timing] POST→响应对象 Xms</span></span>
<span class="line"><span>[LLM/timing] 首 chunk 到达 Xms</span></span>
<span class="line"><span>[LLM/timing] 首文字 token Xms</span></span>
<span class="line"><span>[TTS/warmup] 已触发预热任务 → edge-tts 预热完成 Xms</span></span>
<span class="line"><span>[TTS/stream] 段 N ok 字数=X 首块=Yms 合成=Zms</span></span>
<span class="line"><span>[TTS/stream] 首段已推送 距 LLM 起=Xms</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 三层路由新增：</span></span>
<span class="line"><span>[Tier0] 命中关键词 &#39;XXX&#39; → 工具 drone.takeoff ack=&#39;好的，正在起飞&#39;</span></span>
<span class="line"><span>[Tier0] 工具 drone.takeoff 完成: ...</span></span>
<span class="line"><span>[Tier1] flash 完成 总耗时=Xms 字数=Y 回复=&#39;...&#39;</span></span>
<span class="line"><span>[Tier1] 命中 fallback 短语 &#39;做不了&#39; (前 N 字)，丢弃 flash 输出</span></span>
<span class="line"><span>[Tier2] 触发原因=tier2-fallback-or-default</span></span>
<span class="line"><span>[Tier2-direct] 命中关键词 &#39;XXX&#39;，跳过 Tier 1</span></span></code></pre></div><hr><h2 id="已修复但需在新硬件上验证" tabindex="-1">已修复但需在新硬件上验证 <a class="header-anchor" href="#已修复但需在新硬件上验证" aria-label="Permalink to &quot;已修复但需在新硬件上验证&quot;">​</a></h2><ul><li>摄像头报错刷屏（已下线 SceneMonitor）</li><li>TTS warmup 失败（&quot;。&quot; → &quot;嗯。&quot;）</li></ul><hr><h2 id="项目内重点文档" tabindex="-1">项目内重点文档 <a class="header-anchor" href="#项目内重点文档" aria-label="Permalink to &quot;项目内重点文档&quot;">​</a></h2><ul><li>project_markdown/FIRST_RESPONSE_LATENCY.md — 完整方案文档（Part A 一般对话 + Part B ROS 控制 + 决策记录）</li><li>project_markdown/README.md — 项目入口</li><li>project_markdown/SLAM_WEB_VIEWER_DESIGN.md — SLAM 模块设计</li></ul><hr><h2 id="api-凭据-写在-config-config-json-里" tabindex="-1">API 凭据（写在 config/config.json 里） <a class="header-anchor" href="#api-凭据-写在-config-config-json-里" aria-label="Permalink to &quot;API 凭据（写在 config/config.json 里）&quot;">​</a></h2><ul><li>LLM（Tier 2，coder-next）：<a href="https://coding.dashscope.aliyuncs.com/v1" target="_blank" rel="noreferrer">https://coding.dashscope.aliyuncs.com/v1</a> + sk-sp-ac3c84c5e49946ceb4fe63fbee8f9787 + model qwen3-coder-next</li><li>LLM_FAST（Tier 1，flash）：<a href="https://dashscope.aliyuncs.com/compatible-mode/v1" target="_blank" rel="noreferrer">https://dashscope.aliyuncs.com/compatible-mode/v1</a> + sk-4529e46f796b46539ba4307d5d4fe5c2 + model qwen-flash</li></ul><hr><h2 id="协作约定" tabindex="-1">协作约定 <a class="header-anchor" href="#协作约定" aria-label="Permalink to &quot;协作约定&quot;">​</a></h2><ul><li>PC 上不跑项目代码，syncpi 到开发板再测</li><li>改动前先讨论方案，避免大刀阔斧改完才发现方向不对</li><li>改完代码后等用户实测日志反馈，再决定下一步</li></ul>`,65)])])}const m=t(l,[["render",i]]);export{u as __pageData,m as default};
